    action mask, this implementation reconstructs an approximate internal board from
    the observation and searches over plausible future states. It supports triangle_size=2
    and is written to remain robust when only partial environment internals are available.
    """

    def __init__(self, triangle_size=2, config=None):
        if config is None:
            config = {}
        observation_space = Box(
            low=0,
            high=1,
            shape=((4 * triangle_size + 1) * (4 * triangle_size + 1) * 4,),
            dtype=np.int8,
        )
        action_space = Discrete((4 * triangle_size + 1) * (4 * triangle_size + 1) * 6 * 2 + 1)
        super().__init__(observation_space, action_space, config)

        self.triangle_size = triangle_size
        self.board_size = 4 * triangle_size + 1
        self.action_space_dim = action_space.n
        self.max_depth = int(config.get("depth", 3))
        self.max_branching = int(config.get("max_branching", 12))
        self.end_turn_action = self.action_space_dim - 1
        self._goal_cells_me = self._build_goal_cells(for_self=True)
        self._goal_cells_opp = self._build_goal_cells(for_self=False)

    def _build_goal_cells(self, for_self=True):
        n = self.triangle_size
        cells = []
        for q in range(-2 * n, 2 * n + 1):
            for r in range(-2 * n, 2 * n + 1):
                if not self._on_board(q, r):
                    continue
                progress = q + r
                if for_self:
                    if progress >= 3 * n:
                        cells.append((q, r))
                else:
                    if progress <= -3 * n:
                        cells.append((q, r))
        return set(cells)

    def _on_board(self, q, r):
        n = self.triangle_size
        return max(abs(q), abs(r), abs(q - r)) <= 2 * n

    def _to_index(self, q, r):
        return q + 2 * self.triangle_size, r + 2 * self.triangle_size

    def _action_to_move(self, action: int):
        n = self.triangle_size
        if action == (4 * n + 1) ** 2 * 6 * 2:
            return Move.END_TURN
        index = action
        index, is_jump = divmod(index, 2)
        index, direction = divmod(index, 6)
        _q, _r = divmod(index, 4 * n + 1)
        q, r = _q - 2 * n, _r - 2 * n
        return Move(q, r, direction, bool(is_jump))

    def _move_to_action(self, move: Move):
        n = self.triangle_size
        if move == Move.END_TURN:
            return (4 * n + 1) ** 2 * 6 * 2
        q, r, direction, is_jump = move.position.q, move.position.r, move.direction, move.is_jump
        return int(is_jump) + 2 * (direction + 6 * ((r + 2 * n) + (4 * n + 1) * (q + 2 * n)))

    def _decode_observation(self, obs):
        channels = np.asarray(obs["observation"]).reshape(self.board_size, self.board_size, 4)
        my_pieces = set()
        opp_pieces = set()
        for iq in range(self.board_size):
            for ir in range(self.board_size):
                q = iq - 2 * self.triangle_size
                r = ir - 2 * self.triangle_size
                if not self._on_board(q, r):
                    continue
                if channels[iq, ir, 0] > 0:
                    my_pieces.add((q, r))
                elif channels[iq, ir, 1] > 0:
                    opp_pieces.add((q, r))
        return {"me": my_pieces, "opp": opp_pieces}

