        _q, _r = divmod(index, 4 * n + 1)
        q, r = _q - 2 * n, _r - 2 * n
        return Move(q, r, direction, bool(is_jump))

    def _move_to_action(self, move: Move):
        n = self.triangle_size
        if move == Move.END_TURN:
            return (4 * n + 1) ** 2 * 6 * 2
        q, r, direction, is_jump = move.position.q, move.position.r, move.direction, move.is_jump
        return int(is_jump) + 2 * (direction + 6 * ((r + 2 * n) + (4 * n + 1) * (q + 2 * n)))

    def _decode_observation(self, obs):
        channels = np.asarray(obs["observation"]).reshape(self.board_size, self.board_size, 4)
        my_pieces = set()
        opp_pieces = set()
        for iq in range(self.board_size):
            for ir in range(self.board_size):
                q = iq - 2 * self.triangle_size
                r = ir - 2 * self.triangle_size
                if not self._on_board(q, r):
                    continue
                if channels[iq, ir, 0] > 0:
                    my_pieces.add((q, r))
                elif channels[iq, ir, 1] > 0:
                    opp_pieces.add((q, r))
        return {"me": my_pieces, "opp": opp_pieces}

    def _distance_to_goal(self, pos, for_self=True):
        q, r = pos
        target_value = 4 * self.triangle_size if for_self else -4 * self.triangle_size
        progress = q + r
        return abs(target_value - progress)

    def _terminal_score(self, state):
        if self._is_win(state["me"], self._goal_cells_me):
            return 100000.0
        if self._is_win(state["opp"], self._goal_cells_opp):
            return -100000.0
        return None

    def _is_win(self, pieces, goal_cells):
        return len(goal_cells) > 0 and goal_cells.issubset(pieces)

    def _evaluate(self, state):
        terminal = self._terminal_score(state)
        if terminal is not None:
            return terminal

        my_dist = sum(self._distance_to_goal(p, True) for p in state["me"])
        opp_dist = sum(self._distance_to_goal(p, False) for p in state["opp"])

        my_goal_count = sum(1 for p in state["me"] if p in self._goal_cells_me)
        opp_goal_count = sum(1 for p in state["opp"] if p in self._goal_cells_opp)

        my_mobility = len(self._generate_moves(state, True, limit=self.max_branching))
        opp_mobility = len(self._generate_moves(state, False, limit=self.max_branching))

        return (
            8.0 * (opp_dist - my_dist)
            + 30.0 * (my_goal_count - opp_goal_count)
            + 1.5 * (my_mobility - opp_mobility)
        )

    def _generate_moves(self, state, maximizing_player, limit=None):
        own = state["me"] if maximizing_player else state["opp"]
        other = state["opp"] if maximizing_player else state["me"]
        occupied = own | other
        moves = []

        for q, r in own:
            for direction, (dq, dr) in DIRECTION_DELTAS.items():
                nq, nr = q + dq, r + dr
                if self._on_board(nq, nr) and (nq, nr) not in occupied:
                    move = Move(q, r, direction, False)
                    next_state = self._apply_move(state, move, maximizing_player)
                    score = self._evaluate(next_state)
                    moves.append((score, move))

                jq, jr = q + 2 * dq, r + 2 * dr
                if (
                    self._on_board(jq, jr)
                    and (nq, nr) in occupied
                    and (jq, jr) not in occupied
                ):
                    move = Move(q, r, direction, True)
                    next_state = self._apply_move(state, move, maximizing_player)
                    score = self._evaluate(next_state) + 0.25
                    moves.append((score, move))

        if not moves:
            return [Move.END_TURN]

        reverse = maximizing_player
        moves.sort(key=lambda x: x[0], reverse=reverse)
        ordered = [m for _, m in moves]
        if limit is not None:
            ordered = ordered[:limit]
        return ordered

    def _apply_move(self, state, move, maximizing_player):
        if move == Move.END_TURN:
            return {"me": set(state["me"]), "opp": set(state["opp"])}

        own_key = "me" if maximizing_player else "opp"
        next_state = {"me": set(state["me"]), "opp": set(state["opp"])}
        own = next_state[own_key]

        start = (move.position.q, move.position.r)
        dq, dr = DIRECTION_DELTAS[move.direction]
        step = 2 if move.is_jump else 1
        end = (start[0] + step * dq, start[1] + step * dr)

        if start in own:
            own.remove(start)
            own.add(end)
        return next_state

    def _alphabeta(self, state, depth, alpha, beta, maximizing_player):
        terminal = self._terminal_score(state)
        if depth == 0 or terminal is not None:
            return self._evaluate(state), None

        legal_moves = self._generate_moves(state, maximizing_player, limit=self.max_branching)
        if not legal_moves:
            return self._evaluate(state), Move.END_TURN

        best_move = legal_moves[0]

        if maximizing_player:
            value = -math.inf
            for move in legal_moves:
                child = self._apply_move(state, move, True)
                child_value, _ = self._alphabeta(child, depth - 1, alpha, beta, False)
                if child_value > value:
                    value = child_value
                    best_move = move
                alpha = max(alpha, value)
                if beta <= alpha:
                    break
            return value, best_move
        else:
            value = math.inf
            for move in legal_moves:
                child = self._apply_move(state, move, False)
                child_value, _ = self._alphabeta(child, depth - 1, alpha, beta, True)
                if child_value < value:
                    value = child_value
                    best_move = move
                beta = min(beta, value)
                if beta <= alpha:
                    break
            return value, best_move

    def _pick_legal_fallback(self, action_mask):
        legal = np.where(np.asarray(action_mask) == 1)[0]
        if len(legal) == 0:
            return self.end_turn_action

        best_action = int(legal[0])
        best_score = -math.inf
        for action in legal:
            if int(action) == self.end_turn_action:
                continue
            move = self._action_to_move(int(action))
            dq, dr = DIRECTION_DELTAS[move.direction]
            progress = dq + dr
            score = progress + (0.5 if move.is_jump else 0.0)
            if score > best_score:
                best_score = score
                best_action = int(action)
        return best_action

    def compute_actions(
        self,
        obs_batch,
        state_batches=None,
        prev_action_batch=None,
        prev_reward_batch=None,
        info_batch=None,
        episodes=None,
        **kwargs,
    ):
        actions = []
        for obs in obs_batch:
            action_mask = np.asarray(obs["action_mask"])
            state = self._decode_observation(obs)
            _, best_move = self._alphabeta(state, self.max_depth, -math.inf, math.inf, True)

            if best_move is None:
                action = self._pick_legal_fallback(action_mask)
            else:
                action = self._move_to_action(best_move)
                if action >= len(action_mask) or action_mask[action] != 1:
                    action = self._pick_legal_fallback(action_mask)
            actions.append(action)
        return actions, [], {}

    def compute_single_action(self, obs, state=None, prev_action=None, prev_reward=None, info=None, episode=None, **kwargs):
        return self.compute_actions(
            [obs],
            state_batches=[state],
            prev_action_batch=[prev_action],
            prev_reward_batch=[prev_reward],
            info_batch=[info],
